import { createBrowserRouter, RouterProvider } from "react-router"
import { lazy, Suspense } from "react"
import AuthPage from "../../features/auth/pages/AuthPage"
import ResetPassword from "../../features/auth/components/ResetPassword"
import { Dashboard } from "../../pages/Dashboard"
import ProtectedRoute from "../routes/ProtectedRoute.jsx"
import Protected from "../../features/hospital/components/Protected.jsx"
import HomeLayout from "../../layouts/HomeLayout"

const Hospital = lazy(() => import("../../features/hospital/pages/Hospital"))
const DoctorsPage = lazy(() => import("../../features/hospital/pages/DoctorsPage"))
const DoctorProfilePage = lazy(() => import("../../features/hospital/pages/DoctorProfilePage"))
const AppointmentPage = lazy(() => import("../../features/hospital/pages/AppointmentPage"))
const DiseasePage = lazy(() => import("../../features/health/pages/DiseasePage"))
const MedicinePage = lazy(() => import("../../features/health/pages/MedicinePage"))
const AdminDashboard = lazy(() => import("../../features/admin/pages/AdminDashboard"))
const UserManagement = lazy(() => import("../../features/admin/pages/UserManagement"))
const HospitalManagement = lazy(() => import("../../features/admin/pages/HospitalManagement"))
const DoctorManagement = lazy(() => import("../../features/admin/pages/DoctorManagement"))

const Loadable = (Component) => (props) => (
  <Suspense fallback={
    <div className="flex h-screen items-center justify-center">
      <div className="w-8 h-8 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin" />
    </div>
  }>
    <Component {...props} />
  </Suspense>
)

const LazyHospital = Loadable(Hospital)
const LazyDoctorsPage = Loadable(DoctorsPage)
const LazyDoctorProfilePage = Loadable(DoctorProfilePage)
const LazyAppointmentPage = Loadable(AppointmentPage)
const LazyDiseasePage = Loadable(DiseasePage)
const LazyMedicinePage = Loadable(MedicinePage)
const LazyAdminDashboard = Loadable(AdminDashboard)
const LazyUserManagement = Loadable(UserManagement)
const LazyHospitalManagement = Loadable(HospitalManagement)
const LazyDoctorManagement = Loadable(DoctorManagement)


// Define the router with a protected layout for authenticated routes
export const router = createBrowserRouter([
    {
        path: "/",
        element: <HomeLayout />
    },
    {
        path: "/auth",
        element: <AuthPage />
    },
    {
        path: "/reset-password",
        element: <ResetPassword />
    },
    {
        path: "/dashboard",
        element: <ProtectedRoute />,
        children: [
            {
                index: true,
                element: <Dashboard />
            }
        ]
    },
    {
        path: "/hospital",
        element: <Protected role="hospitalAdmin"><LazyHospital /></Protected>
    },
    {
        path: "/hospital/doctors",
        element: <Protected role="hospitalAdmin"><LazyDoctorsPage /></Protected>
    },
    {
        path: "/hospital/doctors/:doctorId",
        element: <Protected role="hospitalAdmin"><LazyDoctorProfilePage /></Protected>
    },
    {
        path: "/hospital/appointments",
        element: <Protected role="hospitalAdmin"><LazyAppointmentPage /></Protected>
    },
    {
        path: "/admin",
        element: <Protected role="admin"><LazyAdminDashboard /></Protected>
    },
    {
        path: "/admin/users",
        element: <Protected role="admin"><LazyUserManagement /></Protected>
    },
    {
        path: "/admin/hospitals",
        element: <Protected role="admin"><LazyHospitalManagement /></Protected>
    },
    {
        path: "/admin/doctors",
        element: <Protected role="admin"><LazyDoctorManagement /></Protected>
    },
    {
        path: "/health/diseases",
        element: <Protected role="admin"><LazyDiseasePage /></Protected>
    },
    {
        path: "/health/medicines",
        element: <Protected role="admin"><LazyMedicinePage /></Protected>
    }
])

const Approuter = () => {
    return (
        <RouterProvider router={router} />
    )
}

export default Approuter

import { useForm, useFieldArray } from "react-hook-form";
import axios from "axios";
import { useState, useRef, useEffect } from "react";
import { gsap } from "gsap";
import { AlertCircle } from "lucide-react";

const PremiumInput = ({ label, icon, ...props }) => (
  <div className="flex flex-col gap-2 group/input">
    <label className="text-[10px] font-black text-[#6c7a71] uppercase tracking-[0.15em] px-2">{label}</label>
    <div className="relative">
      <div className="absolute left-5 top-1/2 -translate-y-1/2 text-[#a0a3a5] group-focus-within/input:text-orange-600 transition-colors duration-300">
        {icon}
      </div>
      <input
        {...props}
        className="w-full pl-14 pr-6 py-4 rounded-[20px] bg-orange-50 border-2 border-transparent 
                   text-[#171c1f] text-sm font-semibold outline-none transition-all duration-300
                   focus:bg-white focus:border-orange-200 focus:ring-8 focus:ring-orange-100"
      />
    </div>
  </div>
);

const PremiumTextarea = ({ label, icon, ...props }) => (
  <div className="flex flex-col gap-2 group/input">
    <label className="text-[10px] font-black text-[#6c7a71] uppercase tracking-[0.15em] px-2">{label}</label>
    <div className="relative">
      <div className="absolute left-5 top-5 text-[#a0a3a5] group-focus-within/input:text-orange-600 transition-colors duration-300">
        {icon}
      </div>
      <textarea
        {...props}
        className="w-full pl-14 pr-6 py-4 rounded-[20px] bg-orange-50 border-2 border-transparent 
                   text-[#171c1f] text-sm font-semibold outline-none transition-all duration-300 resize-none
                   focus:bg-white focus:border-orange-200 focus:ring-8 focus:ring-orange-100"
      />
    </div>
  </div>
);

export default function DiseaseForm({ isOpen, onClose, onSuccess }) {
  const { register, handleSubmit, control, reset } = useForm();
  const [images, setImages] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const modalRef = useRef(null);
  const overlayRef = useRef(null);

  // Dynamic fields
  const symptoms = useFieldArray({ control, name: "symptoms" });
  const causes = useFieldArray({ control, name: "causes" });
  const precautions = useFieldArray({ control, name: "precautions" });
  const diagnosis = useFieldArray({ control, name: "diagnosis" });
  const remedies = useFieldArray({ control, name: "homeRemedies" });

  useEffect(() => {
    if (isOpen) {
      gsap.fromTo(overlayRef.current, { opacity: 0 }, { opacity: 1, duration: 0.4 });
      gsap.fromTo(modalRef.current, { y: 40, opacity: 0, scale: 0.95 }, { y: 0, opacity: 1, scale: 1, duration: 0.5, ease: 'back.out(1.7)' });
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleClose = () => {
    gsap.to(modalRef.current, { y: 20, opacity: 0, scale: 0.95, duration: 0.3, onComplete: onClose });
    gsap.to(overlayRef.current, { opacity: 0, duration: 0.3 });
    reset();
    setImages([]);
  };

  const handleImageChange = (e) => {
    setImages([...e.target.files]);
  };

  const onSubmit = async (data) => {
    try {
      setIsLoading(true);
      const formData = new FormData();

      Object.keys(data).forEach((key) => {
        if (Array.isArray(data[key])) {
          data[key].forEach((item) => {
            if (item) formData.append(key, item);
          });
        } else {
          formData.append(key, data[key]);
        }
      });

      images.forEach((img) => {
        formData.append("images", img);
      });

      await axios.post("/api/disease", formData);
      alert("Disease added ✅");
      onSuccess?.();
      handleClose();
    } catch (err) {
      console.log(err);
      alert("Error adding disease");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6">
      <div
        ref={overlayRef}
        className="absolute inset-0 bg-[#0f171f]/60 backdrop-blur-xl"
        onClick={handleClose}
      />

      <div
        ref={modalRef}
        className="relative w-full max-w-4xl bg-white rounded-[40px] shadow-[0_40px_100px_rgba(0,0,0,0.2)] overflow-hidden max-h-[90vh] overflow-y-auto"
      >
        <div className="sticky top-0 bg-orange-50 px-10 py-8 border-b border-white/50 flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-black text-[#171c1f] tracking-tight">Register Health Condition</h2>
            <p className="text-[#6c7a71] text-xs font-bold uppercase tracking-widest mt-1">Disease Database Integration</p>
          </div>
          <button onClick={handleClose} className="w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-[#a0a3a5] hover:text-orange-600 transition-colors">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="p-10 space-y-8">
          <div>
            <h3 className="text-lg font-black text-[#171c1f] mb-4 flex items-center gap-2">
              <AlertCircle size={20} className="text-orange-600" />
              Basic Information
            </h3>
            <div className="space-y-6">
              <PremiumInput
                label="Disease Name"
                placeholder="e.g., Diabetes Mellitus"
                {...register("name", { required: true })}
                icon={<AlertCircle size={20} />}
              />
              <PremiumTextarea
                label="Description"
                placeholder="Detailed description of the disease..."
                {...register("description", { required: true })}
                icon={<AlertCircle size={20} />}
                rows="4"
              />
            </div>
          </div>

          <div>
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-black text-[#171c1f] flex items-center gap-2">
                <AlertCircle size={20} className="text-orange-600" />
                Symptoms
              </h3>
              <button
                type="button"
                onClick={() => symptoms.append("")}
                className="px-4 py-2 bg-orange-50 text-orange-600 font-bold text-xs rounded-lg hover:bg-orange-100 transition"
              >
                + Add Symptom
              </button>
            </div>
            <div className="space-y-2">
              {symptoms.fields.map((field, idx) => (
                <div key={field.id} className="flex gap-2">
                  <input
                    {...register(`symptoms.${idx}`)}
                    placeholder={`Symptom ${idx + 1}`}
                    className="flex-1 px-4 py-2 rounded-lg bg-orange-50 border border-orange-100 text-sm outline-none focus:border-orange-300 focus:ring-2 focus:ring-orange-100"
                  />
                  {symptoms.fields.length > 0 && (
                    <button
                      type="button"
                      onClick={() => symptoms.remove(idx)}
                      className="px-3 bg-red-50 text-red-500 rounded-lg hover:bg-red-100 transition text-sm font-bold"
                    >
                      ✕
                    </button>
                  )}
                </div>
              ))}
            </div>
          </div>

          <div>
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-black text-[#171c1f] flex items-center gap-2">
                <AlertCircle size={20} className="text-orange-600" />
                Causes
              </h3>
              <button
                type="button"
                onClick={() => causes.append("")}
                className="px-4 py-2 bg-orange-50 text-orange-600 font-bold text-xs rounded-lg hover:bg-orange-100 transition"
              >
                + Add Cause
              </button>
            </div>
            <div className="space-y-2">
              {causes.fields.map((field, idx) => (
                <div key={field.id} className="flex gap-2">
                  <input
                    {...register(`causes.${idx}`)}
                    placeholder={`Cause ${idx + 1}`}
                    className="flex-1 px-4 py-2 rounded-lg bg-orange-50 border border-orange-100 text-sm outline-none focus:border-orange-300 focus:ring-2 focus:ring-orange-100"
                  />
                  {causes.fields.length > 0 && (
                    <button
                      type="button"
                      onClick={() => causes.remove(idx)}
                      className="px-3 bg-red-50 text-red-500 rounded-lg hover:bg-red-100 transition text-sm font-bold"
                    >
                      ✕
                    </button>
                  )}
                </div>
              ))}
            </div>
          </div>

          <div className="flex gap-4 mt-10">
            <button
              type="button"
              onClick={handleClose}
              className="flex-1 py-5 rounded-3xl bg-orange-50 text-orange-600 font-black text-xs uppercase tracking-widest hover:bg-orange-100 transition-all duration-300"
            >
              Discard
            </button>
            <button
              type="submit"
              disabled={isLoading}
              className="flex-1 py-5 rounded-[24px] bg-linear-to-r from-orange-600 to-orange-500 text-white font-black text-xs uppercase tracking-widest shadow-xl shadow-orange-100 hover:shadow-2xl hover:scale-[1.02] active:scale-[0.98] transition-all duration-300 disabled:opacity-50"
            >
              {isLoading ? 'Registering...' : 'Register Disease'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import { motion } from "framer-motion";
import { Circle } from "lucide-react";
import React from "react";
import { Link } from "react-router";
import { useSelector, useDispatch } from "react-redux";
import { logout } from "../features/auth/slice/auth.slice";

/* helper */
function cn(...classes) {
  return classes.filter(Boolean).join(" ");
}

/* floating shapes */
function ElegantShape({
  className,
  delay = 0,
  width = 400,
  height = 100,
  rotate = 0,
  gradient = "from-white/[0.08]",
}) {
  return (
    <motion.div
      initial={{ opacity: 0, y: -150, rotate: rotate - 15 }}
      animate={{ opacity: 1, y: 0, rotate }}
      transition={{
        duration: 2.4,
        delay,
        ease: [0.23, 0.86, 0.39, 0.96],
      }}
      className={cn("absolute", className)}
    >
      <motion.div
        animate={{ y: [0, 15, 0] }}
        transition={{ duration: 12, repeat: Infinity, ease: "easeInOut" }}
        style={{ width, height }}
        className="relative"
      >
        <div
          className={cn(
            "absolute inset-0 rounded-full",
            "bg-gradient-to-r to-transparent",
            gradient,
            "backdrop-blur-[2px] border border-white/[0.15]",
            "shadow-[0_8px_32px_rgba(255,255,255,0.1)]"
          )}
        />
      </motion.div>
    </motion.div>
  );
}

export default function HeroGeometric() {
  const { isAuthenticated } = useSelector((state) => state.auth);
  const dispatch = useDispatch();

  const fadeUpVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: (i) => ({
      opacity: 1,
      y: 0,
      transition: {
        duration: 1,
        delay: 0.5 + i * 0.2,
        ease: [0.25, 0.4, 0.25, 1],
      },
    }),
  };

  return (
    <div className="relative min-h-screen w-full flex items-center justify-center overflow-hidden bg-[#030303]">
      
      {/* background glow */}
      <div className="absolute inset-0 bg-gradient-to-br from-cyan-500/[0.05] via-transparent to-blue-500/[0.05] blur-3xl" />

      {/* floating shapes */}
      <div className="absolute inset-0 overflow-hidden">
        <ElegantShape
          delay={0.3}
          width={600}
          height={140}
          rotate={12}
          gradient="from-cyan-500/[0.15]"
          className="left-[-10%] md:left-[-5%] top-[20%]"
        />

        <ElegantShape
          delay={0.5}
          width={500}
          height={120}
          rotate={-15}
          gradient="from-blue-500/[0.15]"
          className="right-[-5%] md:right-[0%] top-[70%]"
        />

        <ElegantShape
          delay={0.4}
          width={300}
          height={80}
          rotate={-8}
          gradient="from-indigo-500/[0.15]"
          className="left-[10%] bottom-[10%]"
        />
      </div>

      {/* MAIN CONTENT */}
      <div className="relative z-10 container mx-auto px-4 md:px-6 text-center">
        <div className="max-w-3xl mx-auto">

          {/* badge */}
          <motion.div
            custom={0}
            variants={fadeUpVariants}
            initial="hidden"
            animate="visible"
            className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-white/[0.03] border border-white/[0.08] mb-8"
          >
            <Circle className="h-2 w-2 fill-cyan-400 animate-pulse" />
            <span className="text-sm text-white/60 tracking-wide">
              Smart Healthcare Platform
            </span>
          </motion.div>

          {/* heading */}
          <motion.div
            custom={1}
            variants={fadeUpVariants}
            initial="hidden"
            animate="visible"
          >
            <h1 className="text-4xl sm:text-6xl md:text-7xl font-bold mb-6 tracking-tight">
              <span className="bg-clip-text text-transparent bg-gradient-to-b from-white to-white/80">
                Your Health, Simplified
              </span>
              <br />
              <span className="bg-clip-text text-transparent bg-gradient-to-r from-cyan-300 via-white/90 to-blue-300">
                With HealthAxis
              </span>
            </h1>
          </motion.div>

          {/* description */}
          <motion.p
            custom={2}
            variants={fadeUpVariants}
            initial="hidden"
            animate="visible"
            className="text-base sm:text-lg md:text-xl text-white/40 mb-8 leading-relaxed"
          >
            Access hospitals, manage appointments, and take control of your health — all in one powerful platform.
          </motion.p>

          {/* buttons */}
          <motion.div
            custom={3}
            variants={fadeUpVariants}
            initial="hidden"
            animate="visible"
          >
            {isAuthenticated ? (
              <div className="flex justify-center gap-4 flex-wrap">
                <Link to="/dashboard">
                  <button className="px-8 py-3 rounded-full bg-gradient-to-r from-cyan-400 to-blue-500 text-black font-semibold hover:scale-105 transition shadow-xl">
                    Dashboard
                  </button>
                </Link>

                <button
                  onClick={() => dispatch(logout())}
                  className="px-8 py-3 rounded-full bg-white/10 border border-white/20 hover:bg-white/20 text-white transition"
                >
                  Logout
                </button>
              </div>
            ) : (
              <div className="flex justify-center gap-4 flex-wrap">
                <Link to="/auth">
                  <button className="px-8 py-3 rounded-full bg-gradient-to-r from-cyan-400 to-blue-500 text-black font-semibold hover:scale-105 transition shadow-xl">
                    Get Started
                  </button>
                </Link>

                
              </div>
            )}
          </motion.div>

        </div>
      </div>

      {/* bottom fade */}
      <div className="absolute inset-0 bg-gradient-to-t from-[#030303] via-transparent to-[#030303]/80 pointer-events-none" />
    </div>
  );
}

import React from "react";
import { motion } from "framer-motion";

const Loader = ({ size = "md", fullScreen = false, message = "Loading..." }) => {
  const sizeClasses = {
    sm: "w-8 h-8",
    md: "w-12 h-12",
    lg: "w-16 h-16",
    xl: "w-20 h-20",
  };

  const containerClasses = fullScreen
    ? "fixed inset-0 flex items-center justify-center bg-black/50 z-50"
    : "flex items-center justify-center";

  const spinnerVariants = {
    animate: {
      rotate: 360,
      transition: {
        duration: 1,
        repeat: Infinity,
        ease: "linear",
      },
    },
  };

  return (
    <div className={containerClasses}>
      <div className="flex flex-col items-center gap-4">
        <motion.div
          className={`${sizeClasses[size]} border-4 border-gray-300 border-t-indigo-500 rounded-full`}
          variants={spinnerVariants}
          animate="animate"
        />
        {message && fullScreen && (
          <p className="text-white text-sm font-medium">{message}</p>
        )}
      </div>
    </div>
  );
};

export default Loader;

