export default function MedicineForm({ isOpen, onClose, onSuccess }) {
  const { register, handleSubmit, control, reset } = useForm();
  const [images, setImages] = useState([]);
  const [diseases, setDiseases] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const modalRef = useRef(null);
  const overlayRef = useRef(null);

  const { fields, append, remove } = useFieldArray({
    control,
    name: "sideEffects",
  });

  useEffect(() => {
    if (isOpen) {
      gsap.fromTo(overlayRef.current, { opacity: 0 }, { opacity: 1, duration: 0.4 });
      gsap.fromTo(modalRef.current, { y: 40, opacity: 0, scale: 0.95 }, { y: 0, opacity: 1, scale: 1, duration: 0.5, ease: 'back.out(1.7)' });
    }
  }, [isOpen]);

  useEffect(() => {
    const fetchDiseases = async () => {
      try {
        const res = await axios.get("/api/disease");
        setDiseases(res.data.data || []);
      } catch (err) {
        console.log(err);
      }
    };
    fetchDiseases();
  }, []);

  if (!isOpen) return null;

  const handleClose = () => {
    gsap.to(modalRef.current, { y: 20, opacity: 0, scale: 0.95, duration: 0.3, onComplete: onClose });
    gsap.to(overlayRef.current, { opacity: 0, duration: 0.3 });
    reset();
    setImages([]);
  };

  const handleImageChange = (e) => {
    setImages([...e.target.files]);
  };

  const onSubmit = async (data) => {
    try {
      setIsLoading(true);
      const formData = new FormData();

      Object.keys(data).forEach((key) => {
        if (Array.isArray(data[key])) {
          data[key].forEach((item) => {
            if (item) formData.append(key, item);
          });
        } else {
          formData.append(key, data[key]);
        }
      });

      images.forEach((img) => formData.append("images", img));

      await axios.post("/api/medicine", formData);
      alert("Medicine added ✅");
      onSuccess?.();
      handleClose();
    } catch (err) {
      console.log(err);
      alert("Error adding medicine");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6">
      <div
        ref={overlayRef}
        className="absolute inset-0 bg-[#0f171f]/60 backdrop-blur-xl"
        onClick={handleClose}
      />

      <div
        ref={modalRef}
        className="relative w-full max-w-4xl bg-white rounded-[40px] shadow-[0_40px_100px_rgba(0,0,0,0.2)] overflow-hidden max-h-[90vh] overflow-y-auto"
      >
        <div className="sticky top-0 bg-blue-50 px-10 py-8 border-b border-white/50 flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-black text-[#171c1f] tracking-tight">Register Pharmaceutical</h2>
            <p className="text-[#6c7a71] text-xs font-bold uppercase tracking-widest mt-1">Medicine Database Integration</p>
          </div>
          <button onClick={handleClose} className="w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-[#a0a3a5] hover:text-blue-600 transition-colors">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="p-10 space-y-8">
          <div>
            <h3 className="text-lg font-black text-[#171c1f] mb-4 flex items-center gap-2">
              <Pill size={20} className="text-blue-600" />
              Basic Information
            </h3>
            <div className="grid grid-cols-2 gap-6">
              <PremiumInput
                label="Medicine Name"
                placeholder="e.g., Aspirin"
                {...register("name", { required: true })}
                icon={<Pill size={20} />}
              />
              <PremiumInput
                label="Generic Name"
                placeholder="e.g., Acetylsalicylic Acid"
                {...register("genericName")}
                icon={<Pill size={20} />}
              />
            </div>
          </div>

          <PremiumTextarea
            label="Description"
            placeholder="Detailed description of the medicine..."
            {...register("description", { required: true })}
            icon={<Pill size={20} />}
            rows="4"
          />

          <div className="grid grid-cols-2 gap-6">
            <PremiumInput
              label="Dosage"
              placeholder="e.g., 2 times daily"
              {...register("dosage", { required: true })}
              icon={<Pill size={20} />}
            />
            <PremiumInput
              label="Storage Instructions"
              placeholder="e.g., Keep in cool place"
              {...register("storage")}
              icon={<Pill size={20} />}
            />
          </div>

          <div>
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-black text-[#171c1f] flex items-center gap-2">
                <Pill size={20} className="text-blue-600" />
                Side Effects
              </h3>
              <button
                type="button"
                onClick={() => append("")}
                className="px-4 py-2 bg-blue-50 text-blue-600 font-bold text-xs rounded-lg hover:bg-blue-100 transition"
              >
                + Add Side Effect
              </button>
            </div>
            <div className="space-y-2">
              {fields.map((field, idx) => (
                <div key={field.id} className="flex gap-2">
                  <input
                    {...register(`sideEffects.${idx}`)}
                    placeholder={`Side Effect ${idx + 1}`}
                    className="flex-1 px-4 py-2 rounded-lg bg-blue-50 border border-blue-100 text-sm outline-none focus:border-blue-300 focus:ring-2 focus:ring-blue-100"
                  />
                  {fields.length > 0 && (
                    <button
                      type="button"
                      onClick={() => remove(idx)}
                      className="px-3 bg-red-50 text-red-500 rounded-lg hover:bg-red-100 transition text-sm font-bold"
                    >
                      ✕
                    </button>
                  )}
                </div>
              ))}
            </div>
          </div>

          <div className="flex items-center gap-4 p-5 bg-blue-50 rounded-[20px] border-2 border-blue-100">
            <input 
              type="checkbox" 
              {...register("isPrescriptionRequired")} 
              className="w-5 h-5 rounded cursor-pointer"
              id="prescriptionReq"
            />
            <label htmlFor="prescriptionReq" className="text-sm font-bold text-[#171c1f] cursor-pointer">
              Prescription Required for this Medicine
            </label>
          </div>

          <div className="flex gap-4 mt-10">
            <button
              type="button"
              onClick={handleClose}
              className="flex-1 py-5 rounded-3xl bg-blue-50 text-blue-600 font-black text-xs uppercase tracking-widest hover:bg-blue-100 transition-all duration-300"
            >
              Discard
            </button>
            <button
              type="submit"
              disabled={isLoading}
              className="flex-1 py-5 rounded-3xl bg-linear-to-r from-blue-600 to-blue-500 text-white font-black text-xs uppercase tracking-widest shadow-xl shadow-blue-100 hover:shadow-2xl hover:scale-[1.02] active:scale-[0.98] transition-all duration-300 disabled:opacity-50"
            >
              {isLoading ? 'Registering...' : 'Register Medicine'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import React, { useState, createContext, useContext } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { Menu, X } from "lucide-react";
import { cn } from "@/lib/utils";

const SidebarContext = createContext();

export const useSidebar = () => {
    const context = useContext(SidebarContext);
    if (!context) {
        throw new Error("useSidebar must be used inside SidebarProvider");
    }
    return context;
};

export const SidebarProvider = ({
    children,
    open: openProp,
    setOpen: setOpenProp,
    animate = true,
}) => {
    const [openState, setOpenState] = useState(false);

    const open = openProp !== undefined ? openProp : openState;
    const setOpen = setOpenProp !== undefined ? setOpenProp : setOpenState;

    return (
        <SidebarContext.Provider value={{ open, setOpen, animate }}>
            {children}
        </SidebarContext.Provider>
    );
};

export const Sidebar = ({ children, open, setOpen, animate }) => {
    return (
        <SidebarProvider open={open} setOpen={setOpen} animate={animate}>
            {children}
        </SidebarProvider>
    );
};

export const SidebarBody = (props) => {
    return (
        <>
            <DesktopSidebar {...props} />
            <MobileSidebar {...props} />
        </>
    );
};

export const DesktopSidebar = ({ className, children, ...props }) => {
    const { open, setOpen, animate } = useSidebar();

    return (
        <motion.div
            className={`h-full px-4 py-4 hidden md:flex md:flex-col bg-neutral-100 dark:bg-neutral-800 flex-shrink-0 ${className || ""}`}
            animate={{
                width: animate ? (open ? "300px" : "60px") : "300px",
            }}
            onMouseEnter={() => setOpen(true)}
            onMouseLeave={() => setOpen(false)}
            {...props}
        >
            {children}
        </motion.div>
    );
};

export const MobileSidebar = ({ className, children, ...props }) => {
    const { open, setOpen } = useSidebar();

    return (
        <>
            <div
                className="h-10 px-4 py-4 flex md:hidden items-center justify-between bg-neutral-100 dark:bg-neutral-800 w-full"
                {...props}
            >
                <div className="flex justify-end w-full">
                    <Menu
                        className="cursor-pointer text-neutral-800 dark:text-neutral-200"
                        onClick={() => setOpen(!open)}
                    />
                </div>

                <AnimatePresence>
                    {open && (
                        <motion.div
                            initial={{ x: "-100%", opacity: 0 }}
                            animate={{ x: 0, opacity: 1 }}
                            exit={{ x: "-100%", opacity: 0 }}
                            transition={{ duration: 0.3 }}
                            className={`fixed inset-0 w-full h-full bg-white dark:bg-neutral-900 p-10 z-50 flex flex-col justify-between ${className || ""}`}
                        >
                            <div
                                className="absolute right-10 top-10 cursor-pointer"
                                onClick={() => setOpen(false)}
                            >
                                <X />
                            </div>

                            {children}
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </>
    );
};

export const SidebarLink = ({ link, className, active }) => {
    const { open, animate } = useSidebar();

    return (
        <a
            href={link.href}
            onClick={(e) => {
                if (link.onClick) {
                    e.preventDefault();
                    link.onClick();
                }
            }}
            className={cn(
                "flex items-center gap-2 py-2 px-2 rounded-lg transition-all duration-200 group/sidebar",
                active
                    ? "bg-gradient-to-r from-indigo-500/20 to-cyan-500/10 border border-indigo-500/20 text-white"
                    : "hover:bg-white/5 text-neutral-700 dark:text-neutral-200",
                className
            )}
        >
            <span className={cn(
                "flex-shrink-0 transition-colors",
                active && "[&>svg]:text-indigo-400"
            )}>
                {link.icon}
            </span>

            <motion.span
                animate={{
                    display: animate
                        ? open
                            ? "inline-block"
                            : "none"
                        : "inline-block",
                    opacity: animate
                        ? open
                            ? 1
                            : 0
                        : 1,
                }}
                className={cn(
                    "text-sm transition group-hover/sidebar:translate-x-1 whitespace-nowrap",
                    active
                        ? "text-white font-semibold"
                        : "text-neutral-700 dark:text-neutral-200"
                )}
            >
                {link.label}
            </motion.span>
        </a>
    );
};

import React from "react";
import { motion } from "framer-motion";

const Spinner = ({
  size = "md",
  variant = "default",
  fullScreen = false,
  message = "",
  overlay = true,
}) => {
  const sizeMap = {
    sm: 32,
    md: 48,
    lg: 64,
    xl: 80,
  };

  const spinnerSize = sizeMap[size];

  const containerClasses = fullScreen
    ? `fixed inset-0 flex items-center justify-center ${
        overlay ? "bg-black/50" : ""
      } z-50`
    : "flex items-center justify-center";

  // Spinner variants
  const spinnerVariants = {
    rotate: {
      animate: {
        rotate: 360,
        transition: { duration: 1, repeat: Infinity, ease: "linear" },
      },
    },
    pulse: {
      animate: {
        scale: [1, 1.2, 1],
        transition: { duration: 1.5, repeat: Infinity },
      },
    },
    bounce: {
      animate: {
        y: [0, -10, 0],
        transition: { duration: 1, repeat: Infinity },
      },
    },
  };

  const defaultSpinner = (
    <motion.div
      className="border-4 border-gray-300 border-t-indigo-500 rounded-full"
      style={{ width: spinnerSize, height: spinnerSize }}
      variants={spinnerVariants.rotate}
      animate="animate"
    />
  );

  const pulseSpinner = (
    <motion.div
      className="rounded-full bg-indigo-500"
      style={{ width: spinnerSize, height: spinnerSize }}
      variants={spinnerVariants.pulse}
      animate="animate"
    />
  );

  const bounceSpinner = (
    <motion.div
      className="w-3 h-3 rounded-full bg-indigo-500"
      variants={spinnerVariants.bounce}
      animate="animate"
    />
  );

  const spinnerMap = {
    default: defaultSpinner,
    pulse: pulseSpinner,
    bounce: bounceSpinner,
  };

  return (
    <div className={containerClasses}>
      <div className="flex flex-col items-center gap-4">
        {spinnerMap[variant] || defaultSpinner}
        {message && <p className="text-sm font-medium text-white">{message}</p>}
      </div>
    </div>
  );
};

export default Spinner;

import React from "react";
import { motion } from "framer-motion";

const ChartComponent = ({ title, data, type = "line" }) => {
  const maxValue = data.length > 0 ? Math.max(...data) : 0;
  const minValue = data.length > 0 ? Math.min(...data) : 0;
  const range = maxValue - minValue || 1;

  const normalizedData = data.map((value) => ((value - minValue) / range) * 100);

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.05, delayChildren: 0.2 },
    },
  };

  const barVariants = {
    hidden: { scaleY: 0, originY: 1 },
    visible: { scaleY: 1, transition: { type: "spring", stiffness: 100, damping: 10 } },
  };

  return (
    <motion.div
      className="bg-white dark:bg-neutral-800 rounded-2xl p-6 shadow-lg border border-gray-200 dark:border-neutral-700"
      whileHover={{ y: -5, boxShadow: "0 20px 40px rgba(99, 102, 241, 0.2)" }}
      transition={{ type: "spring", stiffness: 300, damping: 30 }}
    >
      <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-6">
        {title}
      </h3>

      <div className="h-64 flex items-end justify-between gap-2 p-4 bg-gray-50 dark:bg-neutral-700/50 rounded-lg">
        <motion.div
          className="flex items-end justify-between gap-2 w-full h-full"
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          {normalizedData.map((normalizedValue, idx) => (
            <motion.div
              key={idx}
              variants={barVariants}
              className="flex-1 bg-gradient-to-t from-indigo-500 to-indigo-300 rounded-t-lg relative group cursor-pointer hover:from-indigo-600 hover:to-indigo-400 transition"
              style={{ height: `${normalizedValue}%` }}
            >
              <motion.div
                className="absolute -top-8 left-1/2 transform -translate-x-1/2 bg-gray-900 dark:bg-gray-700 text-white text-xs font-bold px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition whitespace-nowrap"
                animate={{ opacity: 0 }}
                whileHover={{ opacity: 1 }}
              >
                {data[idx]}
              </motion.div>
            </motion.div>
          ))}
        </motion.div>
      </div>

      <div className="mt-4 pt-4 border-t border-gray-200 dark:border-neutral-700 flex justify-between text-sm">
        <span className="text-gray-600 dark:text-gray-400">
          Max: <span className="font-bold text-gray-900 dark:text-white">{maxValue}</span>
        </span>
        <span className="text-gray-600 dark:text-gray-400">
          Avg: <span className="font-bold text-gray-900 dark:text-white">{data.length > 0 ? Math.round(data.reduce((a, b) => a + b) / data.length) : 0}</span>
        </span>
        <span className="text-gray-600 dark:text-gray-400">
          Min: <span className="font-bold text-gray-900 dark:text-white">{minValue}</span>
        </span>
      </div>
    </motion.div>
  );
};

export default ChartComponent;

import React, { useEffect } from "react";
import { motion } from "framer-motion";
import { Activity, CheckCircle, AlertCircle, Info, XCircle, User, Hospital, Stethoscope, Calendar } from "lucide-react";
import { useAdmin } from "../hooks/useAdmin.js";

const RecentActivity = () => {
  const { activityFeed, handleGetActivityFeed } = useAdmin();

  useEffect(() => {
    handleGetActivityFeed(20);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [handleGetActivityFeed]);

  const getActivityIcon = (type) => {
    const icons = {
      user: User,
      hospital: Hospital,
      doctor: Stethoscope,
      appointment: Calendar,
      system: Info,
    };
    return icons[type] || Info;
  };

  const getColorClass = (type, status) => {
    if (status === "failed") {
      return "bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400";
    }
    const colors = {
      user: "bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400",
      hospital: "bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400",
      doctor: "bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400",
      appointment: "bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400",
      system: "bg-orange-100 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400",
    };
    return colors[type] || colors.system;
  };

  const formatTimestamp = (createdAt) => {
    if (!createdAt) return "Unknown time";
    const date = new Date(createdAt);
    const now = new Date();
    const diffMs = now - date;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return "Just now";
    if (diffMins < 60) return `${diffMins} minute${diffMins > 1 ? "s" : ""} ago`;
    if (diffHours < 24) return `${diffHours} hour${diffHours > 1 ? "s" : ""} ago`;
    if (diffDays < 7) return `${diffDays} day${diffDays > 1 ? "s" : ""} ago`;
    return date.toLocaleDateString();
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.1 },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, x: -20 },
    visible: { opacity: 1, x: 0, transition: { type: "spring", stiffness: 100 } },
  };

  const activities = activityFeed?.data || activityFeed || [];

  return (
    <motion.div
      className="bg-white dark:bg-neutral-800 rounded-2xl p-6 shadow-lg border border-gray-200 dark:border-neutral-700"
      whileHover={{ y: -5 }}
    >
      <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-6 flex items-center gap-2">
        <Activity className="w-6 h-6" />
        Recent Activity
      </h3>

      <motion.div
        className="space-y-4"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        {activities.length === 0 && (
          <p className="text-gray-500 dark:text-gray-400 text-sm text-center py-4">
            No recent activity
          </p>
        )}
        {activities.map((activity) => {
          const IconComponent = getActivityIcon(activity.type);
          return (
            <motion.div
              key={activity._id || activity.id}
              variants={itemVariants}
              className="flex items-start gap-4 p-4 rounded-lg bg-gray-50 dark:bg-neutral-700/50 hover:bg-gray-100 dark:hover:bg-neutral-700 transition group cursor-pointer"
              whileHover={{ x: 5 }}
            >
              <motion.div
                className={`p-2 rounded-lg flex-shrink-0 ${getColorClass(activity.type, activity.status)}`}
                whileHover={{ scale: 1.1, rotate: 10 }}
              >
                <IconComponent className="w-5 h-5" />
              </motion.div>

              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold text-gray-900 dark:text-white truncate">
                  {activity.description || activity.message || "Activity"}
                </p>
                <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                  {formatTimestamp(activity.createdAt)}
                </p>
              </div>

              <motion.div
                className={`text-xs px-3 py-1 rounded-full font-semibold flex-shrink-0 ${
                  activity.status === "failed"
                    ? "bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400"
                    : "bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400"
                }`}
                animate={{ opacity: [1, 0.7, 1] }}
                transition={{ duration: 2, repeat: Infinity }}
              >
                {activity.action || activity.type}
              </motion.div>
            </motion.div>
          );
        })}
      </motion.div>

      <motion.button
        className="w-full mt-4 py-2 text-center text-indigo-600 dark:text-indigo-400 font-semibold hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-lg transition"
        whileHover={{ scale: 1.02 }}
        whileTap={{ scale: 0.98 }}
      >
        View All Activity
      </motion.button>
    </motion.div>
  );
};

export default RecentActivity;

import React from "react";
import { motion } from "framer-motion";
import { ArrowUpRight, ArrowDownLeft } from "lucide-react";

const StatCard = ({ icon: Icon, title, value, change, trend, color }) => {
  const colorGradient = {
    blue: "from-blue-500 to-blue-600",
    indigo: "from-indigo-500 to-indigo-600",
    purple: "from-purple-500 to-purple-600",
    cyan: "from-cyan-500 to-cyan-600",
  };

  return (
    <motion.div
      className="bg-white dark:bg-neutral-800 rounded-2xl p-6 shadow-lg border border-gray-200 dark:border-neutral-700 group hover:shadow-xl transition-all"
      whileHover={{ y: -5 }}
      transition={{ type: "spring", stiffness: 300, damping: 30 }}
    >
      <div className="flex items-start justify-between mb-4">
        <motion.div
          className={`p-3 bg-gradient-to-br ${colorGradient[color]} rounded-lg`}
          whileHover={{ scale: 1.1, rotate: 10 }}
          transition={{ type: "spring", stiffness: 400 }}
        >
          <Icon className="w-6 h-6 text-white" />
        </motion.div>
        <motion.div
          className={`flex items-center gap-1 px-2 py-1 rounded-full ${
            trend === "up"
              ? "bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400"
              : "bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400"
          }`}
          animate={{ y: [0, -3, 0] }}
          transition={{ duration: 2, repeat: Infinity }}
        >
          {trend === "up" ? (
            <ArrowUpRight size={16} />
          ) : (
            <ArrowDownLeft size={16} />
          )}
          <span className="text-sm font-bold">{change}%</span>
        </motion.div>
      </div>

      <h3 className="text-sm font-semibold text-gray-600 dark:text-gray-400 mb-1">
        {title}
      </h3>
      <motion.p
        className="text-3xl font-black text-gray-900 dark:text-white"
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2 }}
      >
        {value.toLocaleString()}
      </motion.p>
    </motion.div>
  );
};

export default StatCard;

