import React, { useState, useRef, useEffect } from "react";
import { useSelector } from "react-redux";
import { useForm } from "react-hook-form";
import { toast } from "react-toastify";
import {
  Mail,
  Phone,
  User,
  Upload,
  Key,
  Check,
  X,
  Camera,
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useProfile } from "../hooks/useProfile.js";

export default function ProfilePage() {
  const { user } = useSelector((state) => state.auth);

  const [editMode, setEditMode] = useState(false);
  const [changePasswordMode, setChangePasswordMode] = useState(false);
  const [profileImage, setProfileImage] = useState(null);
  const [previewImage, setPreviewImage] = useState(null);
  const [completeness, setCompleteness] = useState(0);

  const fileInputRef = useRef(null);

  const { handleUpdateProfile, handleChangePassword, loading } = useProfile();

  useEffect(() => {
    const fields = [user?.name, user?.email, user?.number, user?.profileImage];
    const filled = fields.filter(Boolean).length;
    setCompleteness((filled / fields.length) * 100);
  }, [user]);

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm();

  const {
    register: registerPassword,
    handleSubmit: handleSubmitPassword,
    reset: resetPassword,
    getValues,
    formState: { errors: passwordErrors },
  } = useForm();

  useEffect(() => {
    reset({
      name: user?.name || "",
      email: user?.email || "",
      number: user?.number || "",
    });
  }, [user, reset]);

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setProfileImage(file);
      const preview = URL.createObjectURL(file);
      setPreviewImage(preview);
    }
  };

  useEffect(() => {
    return () => {
      if (previewImage) URL.revokeObjectURL(previewImage);
    };
  }, [previewImage]);

  const handleCancelEdit = () => {
    setEditMode(false);
    setProfileImage(null);
    setPreviewImage(null);
    reset({
      name: user?.name || "",
      email: user?.email || "",
      number: user?.number || "",
    });
  };

  const onSubmit = async (data) => {
    try {
      const formData = new FormData();
      Object.keys(data).forEach((key) => formData.append(key, data[key]));

      if (profileImage) formData.append("profileImage", profileImage);

      await handleUpdateProfile(formData);
      toast.success("Profile updated ✅");
      setEditMode(false);
      setProfileImage(null);
      setPreviewImage(null);
    } catch (err) {
      toast.error(err?.response?.data?.message || "Update failed ❌");
    }
  };

  const onPasswordSubmit = async (data) => {
    try {
      await handleChangePassword(data);
      toast.success("Password updated 🔐");
      setChangePasswordMode(false);
      resetPassword();
    } catch (err) {
      toast.error(err?.response?.data?.message || "Error ❌");
    }
  };

  const inputClass =
    "w-full rounded-xl border border-gray-300/80 dark:border-neutral-700 bg-white dark:bg-neutral-900/80 px-4 py-3 text-gray-800 dark:text-gray-100 placeholder:text-gray-400 dark:placeholder:text-neutral-500 outline-none transition focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/20";

  const labelClass =
    "mb-1 flex items-center gap-2 text-sm font-medium text-gray-700 dark:text-neutral-300";

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-100 via-white to-slate-200 dark:from-neutral-950 dark:via-neutral-900 dark:to-neutral-950 p-4 sm:p-6">
      <div className="max-w-4xl mx-auto space-y-6">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
            My Profile
          </h1>
          <p className="mt-1 text-sm text-gray-500 dark:text-neutral-400">
            Manage your personal details and account security
          </p>
        </div>

        <div className="rounded-2xl border border-gray-200/70 dark:border-neutral-800 bg-white/80 dark:bg-neutral-900/70 backdrop-blur-md p-5 shadow-sm">
          <div className="mb-2 flex justify-between text-sm text-gray-700 dark:text-neutral-300">
            <span>Profile Completeness</span>
            <span className="font-semibold">{Math.round(completeness)}%</span>
          </div>
          <div className="h-2.5 w-full overflow-hidden rounded-full bg-gray-200 dark:bg-neutral-800">
            <div
              className="h-full rounded-full bg-gradient-to-r from-indigo-500 to-cyan-500 transition-all duration-500"
              style={{ width: `${completeness}%` }}
            />
          </div>
        </div>

        <div className="rounded-2xl border border-gray-200/70 dark:border-neutral-800 bg-white/80 dark:bg-neutral-900/70 backdrop-blur-md p-6 shadow-sm">
          <div className="flex flex-col gap-6 sm:flex-row sm:items-center sm:justify-between">
            <div className="flex items-center gap-5">
              <div className="relative">
                <div className="flex h-24 w-24 items-center justify-center overflow-hidden rounded-full border-4 border-white dark:border-neutral-800 bg-gradient-to-br from-indigo-500/20 to-cyan-500/20 text-2xl font-bold text-gray-800 dark:text-white shadow">
                  {previewImage ? (
                    <img
                      src={previewImage}
                      alt="Preview"
                      className="h-full w-full object-cover"
                    />
                  ) : user?.profileImage ? (
                    <img
                      src={user.profileImage}
                      alt={user?.name || "Profile"}
                      className="h-full w-full object-cover"
                    />
                  ) : (
                    user?.name?.charAt(0)?.toUpperCase() || "U"
                  )}
                </div>

                {editMode && (
                  <button
                    type="button"
                    aria-label="Upload profile photo"
                    onClick={() => fileInputRef.current.click()}
                    className="absolute bottom-0 right-0 rounded-full bg-indigo-600 p-2 text-white shadow-md transition hover:bg-indigo-700"
                  >
                    <Camera size={16} />
                  </button>
                )}

                <input
                  ref={fileInputRef}
                  type="file"
                  hidden
                  accept="image/*"
                  onChange={handleImageUpload}
                />
              </div>

              <div>
                <p className="text-xl font-semibold text-gray-900 dark:text-white">
                  {user?.name || "User"}
                </p>
                <p className="text-sm capitalize text-gray-500 dark:text-neutral-400">
                  {user?.role || "Member"}
                </p>
              </div>
            </div>
          </div>

          <div className="mt-8">
            <AnimatePresence mode="wait">
              {!editMode ? (
                <motion.div
                  key="view"
                  initial={{ opacity: 0, y: 8 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -8 }}
                  className="space-y-4"
                >
                  <div className="grid gap-4 sm:grid-cols-2">
                    <div className="rounded-xl border border-gray-200 dark:border-neutral-800 bg-gray-50 dark:bg-neutral-950/60 p-4">
                      <div className={labelClass}>
                        <Mail size={16} />
                        <span>Email</span>
                      </div>
                      <p className="text-gray-800 dark:text-neutral-100 break-all">
                        {user?.email || "Not set"}
                      </p>
                    </div>

                    <div className="rounded-xl border border-gray-200 dark:border-neutral-800 bg-gray-50 dark:bg-neutral-950/60 p-4">
                      <div className={labelClass}>
                        <Phone size={16} />
                        <span>Phone</span>
                      </div>
                      <p className="text-gray-800 dark:text-neutral-100">
                        {user?.number || "Not set"}
                      </p>
                    </div>
                  </div>

                  <button
                    onClick={() => setEditMode(true)}
                    className="mt-2 inline-flex items-center gap-2 rounded-xl bg-indigo-600 px-5 py-2.5 text-sm font-medium text-white transition hover:bg-indigo-700 disabled:opacity-60"
                  >
                    <User size={16} />
                    Edit Profile
                  </button>
                </motion.div>
              ) : (
                <motion.form
                  key="edit"
                  onSubmit={handleSubmit(onSubmit)}
                  initial={{ opacity: 0, y: 8 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -8 }}
                  className="space-y-5"
                >
                  <div>
                    <label className={labelClass}>
                      <User size={16} />
                      <span>Name</span>
                    </label>
                    <input
                      {...register("name", { required: "Name is required" })}
                      placeholder="Enter your name"
                      className={inputClass}
                    />
                    {errors.name && (
                      <p className="mt-1 text-sm text-red-500">
                        {errors.name.message}
                      </p>
                    )}
                  </div>

                  <div>
                    <label className={labelClass}>
                      <Mail size={16} />
                      <span>Email</span>
                    </label>
                    <input
                      {...register("email", {
                        required: "Email is required",
                      })}
                      placeholder="Enter your email"
                      className={inputClass}
                    />
                    {errors.email && (
                      <p className="mt-1 text-sm text-red-500">
                        {errors.email.message}
                      </p>
                    )}
                  </div>

                  <div>
                    <label className={labelClass}>
                      <Phone size={16} />
                      <span>Phone</span>
                    </label>
                    <input
                      {...register("number", {
                        required: "Phone number is required",
                        pattern: {
                          value: /^[0-9]{10}$/,
                          message: "Phone number must be 10 digits",
                        },
                      })}
                      placeholder="Enter phone number"
                      className={inputClass}
                    />
                    {errors.number && (
                      <p className="mt-1 text-sm text-red-500">
                        {errors.number.message}
                      </p>
                    )}
                  </div>

                  <div className="flex flex-wrap gap-3">
                    <button
                      type="submit"
                      disabled={loading}
                      className="inline-flex items-center gap-2 rounded-xl bg-emerald-600 px-5 py-2.5 text-sm font-medium text-white transition hover:bg-emerald-700 disabled:cursor-not-allowed disabled:opacity-60"
                    >
                      <Check size={16} />
                      {loading ? "Saving..." : "Save Changes"}
                    </button>

                    <button
                      type="button"
                      onClick={handleCancelEdit}
                      className="inline-flex items-center gap-2 rounded-xl bg-gray-200 px-5 py-2.5 text-sm font-medium text-gray-800 transition hover:bg-gray-300 dark:bg-neutral-800 dark:text-neutral-200 dark:hover:bg-neutral-700"
                    >
                      <X size={16} />
                      Cancel
                    </button>
                  </div>
                </motion.form>
              )}
            </AnimatePresence>
          </div>
        </div>

        <div className="rounded-2xl border border-gray-200/70 dark:border-neutral-800 bg-white/80 dark:bg-neutral-900/70 backdrop-blur-md p-6 shadow-sm">
          <div className="mb-4 flex items-center gap-2">
            <Key className="text-red-500" size={18} />
            <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
              Security
            </h2>
          </div>

          {!changePasswordMode ? (
            <button
              onClick={() => setChangePasswordMode(true)}
              className="inline-flex items-center gap-2 rounded-xl bg-red-600 px-5 py-2.5 text-sm font-medium text-white transition hover:bg-red-700"
            >
              <Key size={16} />
              Change Password
            </button>
          ) : (
            <form
              onSubmit={handleSubmitPassword(onPasswordSubmit)}
              className="space-y-4"
            >
              <div>
                <label className={labelClass}>Current Password</label>
                <input
                  type="password"
                  {...registerPassword("currentPassword", {
                    required: "Current password is required",
                  })}
                  placeholder="Enter current password"
                  className={inputClass}
                />
                {passwordErrors.currentPassword && (
                  <p className="mt-1 text-sm text-red-500">
                    {passwordErrors.currentPassword.message}
                  </p>
                )}
              </div>

              <div>
                <label className={labelClass}>New Password</label>
                <input
                  type="password"
                  {...registerPassword("newPassword", {
                    required: "New password is required",
                    minLength: {
                      value: 8,
                      message: "Password must be at least 8 characters",
                    },
                  })}
                  placeholder="Enter new password"
                  className={inputClass}
                />
                {passwordErrors.newPassword && (
                  <p className="mt-1 text-sm text-red-500">
                    {passwordErrors.newPassword.message}
                  </p>
                )}
              </div>

              <div>
                <label className={labelClass}>Confirm Password</label>
                <input
                  type="password"
                  {...registerPassword("confirmPassword", {
                    required: "Please confirm your password",
                    validate: (value) =>
                      value === getValues("newPassword") ||
                      "Passwords do not match",
                  })}
                  placeholder="Confirm new password"
                  className={inputClass}
                />
                {passwordErrors.confirmPassword && (
                  <p className="mt-1 text-sm text-red-500">
                    {passwordErrors.confirmPassword.message}
                  </p>
                )}
              </div>

              <div className="flex flex-wrap gap-3">
                <button
                  type="submit"
                  disabled={loading}
                  className="inline-flex items-center gap-2 rounded-xl bg-emerald-600 px-5 py-2.5 text-sm font-medium text-white transition hover:bg-emerald-700 disabled:cursor-not-allowed disabled:opacity-60"
                >
                  <Check size={16} />
                  {loading ? "Updating..." : "Update Password"}
                </button>

                <button
                  type="button"
                  onClick={() => {
                    setChangePasswordMode(false);
                    resetPassword();
                  }}
                  className="inline-flex items-center gap-2 rounded-xl bg-gray-200 px-5 py-2.5 text-sm font-medium text-gray-800 transition hover:bg-gray-300 dark:bg-neutral-800 dark:text-neutral-200 dark:hover:bg-neutral-700"
                >
                  <X size={16} />
                  Cancel
                </button>
              </div>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

import axios from "axios";

const api = axios.create({
    baseURL: "/api",
    withCredentials: true
});

// Response interceptor to handle token refresh
api.interceptors.response.use(
    (response) => response,
    async (error) => {
        const originalRequest = error.config;

        // If the error is 401, we haven't retried yet, and it's not the login or refresh routes themselves
        if (
            error.response?.status === 401 &&
            !originalRequest._retry &&
            originalRequest.url !== "/user/login" &&
            originalRequest.url !== "/user/refresh-token"
        ) {
            originalRequest._retry = true;
            try {
                // Make a call to refresh the token using the base axios to avoid infinite loops
                await axios.post("/api/user/refresh-token", {}, { withCredentials: true });

                // If the refresh is successful, retry the original request
                return api(originalRequest);
            } catch (refreshError) {
                // If the refresh token has expired, just reject the promise. Let the application handle the unauthenticated state.
                if (window.location.pathname !== '/') {
                    window.location.href = "/";
                }
                return Promise.reject(refreshError);
            }
        }

        return Promise.reject(error);
    }
);

export async function login({ email, number, password }) {
    try {
        const payload = {
            password,
            ...(email ? { email } : { number })
        };
        const response = await api.post("/user/login", payload);
        return response.data;
    } catch (error) {
        throw error;
    }
}

export async function register({ name, email, number, password }) {
    try {
        const response = await api.post("/user/register", { name, email, number, password });
        return response.data;
    } catch (error) {
        throw error;
    }
}

export function googleAuth() {
    // Google OAuth requires full page redirect, not an AJAX call
    window.location.href = "/api/auth/google";
}

export async function logout() {
    try {
        const response = await api.post("/user/logout");
        return response.data;
    } catch (error) {
        throw error;
    }
}

export async function getCurrentUser() {
    try {
        const response = await api.get("/user/current-user");
        return response.data;
    } catch (error) {
        throw error;
    }
}

export async function updateProfile(formData) {
    try {
        // Don't manually set Content-Type for FormData - axios handles it automatically
        const response = await api.put("/user/profile", formData);
        return response.data;
    } catch (error) {
        throw error;
    }
}

export async function changePassword({ currentPassword, newPassword }) {
    try {
        const response = await api.put("/user/change-password", { currentPassword, newPassword });
        return response.data;
    } catch (error) {
        throw error;
    }
}

export async function forgotPassword(email) {
    try {
        const response = await api.post("/user/forgot-password", { email });
        return response.data;
    } catch (error) {
        throw error;
    }
}

export async function resetPassword({ resetToken, password }) {
    try {
        const response = await api.post("/user/reset-password", { resetToken, password });
        return response.data;
    } catch (error) {
        throw error;
    }
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useSelector } from 'react-redux';
import { useNavigate } from 'react-router';
import { useDisease } from '../hooks/useDisease';
import DiseaseCard from '../components/DiseaseCard';
import Loading from '../components/Loading';
import DiseaseForm from '../../../components/Disease';
import { gsap } from 'gsap';
import { AlertCircle, Search, Plus } from 'lucide-react';

const DiseasePage = () => {
  const { diseases, loading } = useSelector((state) => state.disease);
  const { getAllDiseases, removeDisease } = useDisease();
  const [showAddModal, setShowAddModal] = useState(false);

  const [search, setSearch] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('All');
  const navigate = useNavigate();

  const gridRef = useRef(null);
  const headerRef = useRef(null);
  const titleRef = useRef(null);

  useEffect(() => {
    getAllDiseases();
  }, []);

  const filteredDiseases = useMemo(() => {
    return (diseases?.data || []).filter(disease => {
      const matchSearch = disease.name?.toLowerCase().includes(search.toLowerCase()) ||
        disease.description?.toLowerCase().includes(search.toLowerCase());
      return matchSearch;
    });
  }, [diseases, search]);

  // Extract unique categories from disease names for filtering
  const categories = useMemo(() => {
    return ['All', ...new Set((diseases?.data || [])
      .map(d => d.name?.charAt(0).toUpperCase())
      .filter(Boolean))];
  }, [diseases]);

  useEffect(() => {
    window.scrollTo(0, 0);
    const tl = gsap.timeline();
    tl.fromTo(headerRef.current, { y: -100, opacity: 0 }, { y: 0, opacity: 1, duration: 0.8, ease: 'expo.out' })
      .fromTo(titleRef.current, { x: -50, opacity: 0 }, { x: 0, opacity: 1, duration: 0.8, ease: 'expo.out' }, '-=0.5');
  }, []);

  useEffect(() => {
    if (!loading && filteredDiseases.length > 0) {
      gsap.fromTo('.disease-card-anim',
        { y: 40, opacity: 0, scale: 0.95 },
        { y: 0, opacity: 1, scale: 1, duration: 0.5, stagger: 0.05, ease: 'power2.out' }
      );
    }
  }, [loading, filteredDiseases]);

  if (loading) {
    return <Loading />;
  }

  return (
    <div className="min-h-screen bg-orange-50 font-sans overflow-x-hidden pb-20">
      {/* ── Floating Glass Header ───────────────────────────────────── */}
      <header
        ref={headerRef}
        className="fixed top-6 left-1/2 -translate-x-1/2 z-40 w-[95%] max-w-7xl px-8 py-5
                   bg-white/60 backdrop-blur-2xl rounded-[32px] border border-white/40
                   shadow-[0_8px_32px_rgba(0,0,0,0.04)] flex items-center justify-between"
      >
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-2xl bg-linear-to-br from-orange-600 to-orange-500 flex items-center justify-center text-white shadow-lg shadow-orange-100">
            <AlertCircle className="w-6 h-6" />
          </div>
          <div className="hidden sm:block">
            <h1 className="text-lg font-black text-[#171c1f] tracking-tighter uppercase italic leading-none">Health Axis AI</h1>
            <p className="text-[10px] text-[#6c7a71] font-bold uppercase tracking-widest mt-0.5">Medical Database</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <button
