    [DASHBOARD_TABS.APPOINTMENTS]: (
      <Suspense fallback={<LoadingFallback />}>
        <AppointmentPage />
      </Suspense>
    ),
    [DASHBOARD_TABS.DISEASES]: (
      <Suspense fallback={<LoadingFallback />}>
        <DiseasePage />
      </Suspense>
    ),
    [DASHBOARD_TABS.MEDICINES]: (
